const t={CHECKOUT:"Đặt hàng website",MANUAL_ORDER:"Đơn FB/IG/POS/Zalo",ORDER_CANCEL:"Hủy đơn — hoàn kho",ORDER_RETURN:"Hoàn đơn COD — cộng kho",ORDER_UNCANCEL:"Hoàn tác hủy — trừ kho",ORDER_EDIT_IN:"Sửa đơn — hoàn kho dòng cũ",ORDER_EDIT_OUT:"Sửa đơn — trừ kho dòng mới",MARKETING_GIFT:"Tặng KOL/KOC",MARKETING_GIFT_CANCEL:"Hủy tặng KOL — hoàn kho",MARKETING_GIFT_EDIT_IN:"Sửa marketing — hoàn kho dòng cũ",MARKETING_GIFT_EDIT_OUT:"Sửa marketing — trừ kho dòng mới",STOCK_RECEIPT:"Nhập kho / tăng tồn",ADMIN_ADJUSTMENT:"Admin chỉnh tồn kho",RETURN:"Hoàn hàng thủ công",REFUND:"Hoàn tiền / trả đơn"};function r(e){const n=e.referenceLabel||e.referenceId;return n?e.referenceType==="marketing_gift"||String(n).startsWith("MK")?`Marketing · ${n}`:e.referenceType==="order"||String(n).startsWith("DH")?`Đơn hàng · ${n}`:e.referenceType==="manual_return"?`Hoàn thủ công · ${n}`:n:"—"}const E=[{value:"all",label:"Tất cả nguyên nhân"},...Object.entries(t).map(([e,n])=>({value:e,label:n}))];export{t as S,E as a,r as f};
